1	import { useState } from "react";
2	import { useResolveMarket } from "@/lib/query/hooks";
3	import { useSession } from "@/features/session/context";
4	import type { Market } from "@/lib/api/types";
5	
6	interface Props {
7	  market: Market;
8	}
9	
10	export function ResolveMarketPanel({ market }: Props) {
11	  const { session } = useSession();
12	  const mutation = useResolveMarket(market.id);
13	  const [selectedOutcome, setSelectedOutcome] = useState<string>("");
14	  const [confirming, setConfirming] = useState(false);
15	  const resolvedSummary = market.resolution
16	    ? `Outcome: ${market.resolution}`
17	    : market.resolutionProbabilities
18	      ? `Distribution: ${formatResolutionProbabilities(market.resolutionProbabilities)}`
19	      : "Resolution finalized";
20	
21	  if (market.status === "resolved") {
22	    return (
23	      <div style={resolvedStyle}>
24	        <span style={{ fontWeight: 600, fontSize: "0.85rem" }}>Resolved</span>
25	        <span style={{ fontSize: "0.85rem", color: "var(--color-text-muted)" }}>
26	          <strong>{resolvedSummary}</strong>
27	        </span>
28	      </div>
29	    );
30	  }
31	
32	  if (market.status !== "active" && market.status !== "closed") {
33	    return null;
34	  }
35	
36	  if (!session.accountId) {
37	    return null;
38	  }
39	
40	  const handleResolve = () => {
41	    if (!confirming) {
42	      setConfirming(true);
43	      return;
44	    }
45	
46	    mutation.mutate(
47	      {
48	        payload: {
49	          accountId: session.accountId,
50	          outcomeId: selectedOutcome,
51	        },
52	        session,
53	      },
54	      {
55	        onSuccess: () => {
56	          setConfirming(false);
57	          setSelectedOutcome("");
58	        },
59	        onError: () => {
60	          setConfirming(false);
61	        },
62	      },
63	    );
64	  };
65	
66	  return (
67	    <div style={panelStyle}>
68	      <div style={{ display: "flex", alignItems: "center", gap: "var(--space-sm)", marginBottom: "var(--space-sm)" }}>
69	        <span style={{ fontWeight: 600, fontSize: "0.85rem" }}>Resolve Market</span>
70	      </div>
71	
72	      <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center", flexWrap: "wrap" }}>
73	        <select
74	          value={selectedOutcome}
75	          onChange={(e) => {
76	            setSelectedOutcome(e.target.value);
77	            setConfirming(false);
78	          }}
79	          style={selectStyle}
80	        >
81	          <option value="">Select winning outcome...</option>
82	          {market.outcomes.map((o) => (
83	            <option key={o.id} value={o.id}>
84	              {o.name} ({o.id})
85	            </option>
86	          ))}
87	        </select>
88	
89	        {confirming ? (
90	          <div style={{ display: "flex", gap: "var(--space-xs)", alignItems: "center" }}>
91	            <span style={{ fontSize: "0.8rem", color: "var(--color-danger)", fontWeight: 500 }}>
92	              Confirm resolve to &ldquo;{selectedOutcome}&rdquo;?
93	            </span>
94	            <button
95	              onClick={handleResolve}
96	              disabled={mutation.isPending}
97	              style={confirmBtnStyle}
98	            >
99	              {mutation.isPending ? "Resolving..." : "Yes, Resolve"}
100	            </button>
101	            <button
102	              onClick={() => setConfirming(false)}
103	              style={cancelBtnStyle}
104	            >
105	              Cancel
106	            </button>
107	          </div>
108	        ) : (
109	          <button
110	            onClick={handleResolve}
111	            disabled={!selectedOutcome || mutation.isPending}
112	            style={{
113	              ...resolveBtnStyle,
114	              opacity: selectedOutcome ? 1 : 0.5,
115	              cursor: selectedOutcome ? "pointer" : "not-allowed",
116	            }}
117	          >
118	            Resolve
119	          </button>
120	        )}
121	      </div>
122	
123	      {mutation.isError && (
124	        <div style={errorStyle}>
125	          {mutation.error instanceof Error ? mutation.error.message : "Resolution failed"}
126	        </div>
127	      )}
128	
129	      {mutation.isSuccess && (
130	        <div style={successStyle}>
131	          Market resolved successfully.
132	        </div>
133	      )}
134	    </div>
135	  );
136	}
137	
138	const panelStyle: React.CSSProperties = {
139	  padding: "var(--space-md)",
140	  borderRadius: "var(--radius-md)",
141	  border: "1px solid var(--color-border)",
142	  background: "var(--color-bg-surface)",
143	};
144	
145	const resolvedStyle: React.CSSProperties = {
146	  ...panelStyle,
147	  display: "flex",
148	  gap: "var(--space-md)",
149	  alignItems: "center",
150	  borderColor: "var(--color-success, #22c55e)",
151	  background: "rgba(34, 197, 94, 0.05)",
152	};
153	
154	const selectStyle: React.CSSProperties = {
155	  padding: "6px 12px",
156	  borderRadius: "var(--radius-sm)",
157	  border: "1px solid var(--color-border)",
158	  background: "var(--color-bg)",
159	  color: "var(--color-text)",
160	  fontSize: "0.85rem",
161	};
162	
163	const resolveBtnStyle: React.CSSProperties = {
164	  padding: "6px 16px",
165	  borderRadius: "var(--radius-sm)",
166	  border: "none",
167	  background: "var(--color-danger, #ef4444)",
168	  color: "#fff",
169	  fontWeight: 600,
170	  fontSize: "0.85rem",
171	};
172	
173	const confirmBtnStyle: React.CSSProperties = {
174	  padding: "6px 14px",
175	  borderRadius: "var(--radius-sm)",
176	  border: "none",
177	  background: "var(--color-danger, #ef4444)",
178	  color: "#fff",
179	  fontWeight: 600,
180	  fontSize: "0.8rem",
181	  cursor: "pointer",
182	};
183	
184	const cancelBtnStyle: React.CSSProperties = {
185	  padding: "6px 14px",
186	  borderRadius: "var(--radius-sm)",
187	  border: "1px solid var(--color-border)",
188	  background: "transparent",
189	  color: "var(--color-text-muted)",
190	  fontSize: "0.8rem",
191	  cursor: "pointer",
192	};
193	
194	const errorStyle: React.CSSProperties = {
195	  marginTop: "var(--space-sm)",
196	  padding: "var(--space-xs) var(--space-sm)",
197	  borderRadius: "var(--radius-sm)",
198	  background: "rgba(239, 68, 68, 0.1)",
199	  border: "1px solid var(--color-danger)",
200	  fontSize: "0.8rem",
201	  color: "var(--color-danger)",
202	};
203	
204	const successStyle: React.CSSProperties = {
205	  marginTop: "var(--space-sm)",
206	  padding: "var(--space-xs) var(--space-sm)",
207	  borderRadius: "var(--radius-sm)",
208	  background: "rgba(34, 197, 94, 0.1)",
209	  border: "1px solid var(--color-success, #22c55e)",
210	  fontSize: "0.8rem",
211	  color: "var(--color-success, #22c55e)",
212	};
213	
214	function formatResolutionProbabilities(resolutionProbabilities: Record<string, number>): string {
215	  return Object.entries(resolutionProbabilities)
216	    .map(([outcomeId, probability]) => `${outcomeId} ${(probability * 100).toFixed(1)}%`)
217	    .join(", ");
218	}
