function formatResolutionProbabilities(resolutionProbabilities: Record<string, number>): string {
  return Object.entries(resolutionProbabilities)
    .map(([outcomeId, probability]) => `${outcomeId} ${(probability * 100).toFixed(1)}%`)
    .join(", ");
}

